const e=JSON.parse('{"key":"v-2ea9bc17","path":"/language/Java/basics/exception/17.exception.html","title":"异常（上）","lang":"zh-CN","frontmatter":{"category":["Java异常"],"summary":"异常（上） \\" 在项目开发中如何正确的定义、处理、记录异常\\" 异常是Java语言提供的一种出错处理机制。在Java编程中，我们时刻都离不开异常，在编写正常逻辑代码的同时，总是需要编写处理各种异常情况的逻辑代码。尽管异常语法比较简单，但用好并不容易。不合理的使用异常会导致诸多问题，比如程序变慢，异常信息丢失。所以，本节，我们就重点讲下如何合理的使用异常。下一节","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-v2-demo.mrhope.site/language/Java/basics/exception/17.exception.html"}],["meta",{"property":"og:site_name","content":"Weiser"}],["meta",{"property":"og:title","content":"异常（上）"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:updated_time","content":"2022-06-24T03:27:35.000Z"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"article:modified_time","content":"2022-06-24T03:27:35.000Z"}]]},"excerpt":"","headers":[{"level":2,"title":"一、异常使用","slug":"一、异常使用","link":"#一、异常使用","children":[]},{"level":2,"title":"二、异常体系","slug":"二、异常体系","link":"#二、异常体系","children":[]},{"level":2,"title":"三、自定义异常","slug":"三、自定义异常","link":"#三、自定义异常","children":[]},{"level":2,"title":"四、异常处理","slug":"四、异常处理","link":"#四、异常处理","children":[]},{"level":2,"title":"五、异常调用链","slug":"五、异常调用链","link":"#五、异常调用链","children":[]},{"level":2,"title":"六、课后思考题","slug":"六、课后思考题","link":"#六、课后思考题","children":[]}],"git":{"createdTime":1656041255000,"updatedTime":1656041255000,"contributors":[{"name":"xwzbupt","email":"xwze@bupt.cn","commits":1}]},"readingTime":{"minutes":14.39,"words":4318},"filePathRelative":"language/Java/basics/exception/17.exception.md","localizedDate":"2022年6月24日"}');export{e as data};
